expression.value:
@if(
    or(
        not(
            equals(
                trim(
                    concat(
                        activity('Record horizon to odw data loading')?.Error?.message,
                        activity('Lookup_orchestration_file')?.Error?.message,
                        activity('Filter_Horizon_Table')?.Error?.message,
                        activity('Horizon Raw to Std')?.Error?.message,
                        activity('Filter_Harmonised_NoteBook')?.Error?.message
                    )
                ),
                ''
            )
        ),
        greater(length(variables('HrmNotebookErrorArray')), 0)
    ),
        true,
        false
)

activityMessage.value:
@if(
    and(
        equals(
            trim(
                concat(
                    activity('Record horizon to odw data loading')?.Error?.message,
                    activity('Lookup_orchestration_file')?.Error?.message,
                    activity('Filter_Horizon_Table')?.Error?.message,
                    activity('Horizon Raw to Std')?.Error?.message,
                    activity('Filter_Harmonised_NoteBook')?.Error?.message
                )
            ),
            ''
        ),
        equals(length(variables('HrmNotebookErrorArray')), 0)
    ),
       'Successfully',
        'Failed'

)

activityDuration.value:
@concat(
    string(div(div(sub(
        ticks(formatDateTime(utcNow(), 'yyyy-MM-dd HH:mm:sss')),
        ticks(formatDateTime(if(equals(pipeline().parameters.start_time, null), utcNow(), pipeline().parameters.start_time), 'yyyy-MM-dd HH:mm:sss'))
    ), 600000000), 60)), 'H:', 
    string(mod(div(sub(
        ticks(formatDateTime(utcNow(), 'yyyy-MM-dd HH:mm:sss')),
        ticks(formatDateTime(if(equals(pipeline().parameters.start_time, null), utcNow(), pipeline().parameters.start_time), 'yyyy-MM-dd HH:mm:sss'))
    ), 600000000), 60)), 'M:00s'
)

