Stage.value:
@if(
  and(
    equals(
      trim(
        concat(
          if(equals(activity('Record horizon to odw data loading').Status,'Failed'), activity('Record horizon to odw data loading').Error.message, ''),
          if(equals(activity('Lookup_orchestration_file').Status,'Failed'),        activity('Lookup_orchestration_file').Error.message,        ''),
          if(equals(activity('Filter_Horizon_Table').Status,'Failed'),              activity('Filter_Horizon_Table').Error.message,              ''),
          if(equals(activity('Horizon Raw to Std').Status,'Failed'),                activity('Horizon Raw to Std').Error.message,                ''),
          if(equals(activity('Filter_Harmonised_NoteBook').Status,'Failed'),        activity('Filter_Harmonised_NoteBook').Error.message,        '')
        )
      ),
      ''
    ),
    equals(length(variables('HrmNotebookErrorArray')), 0)
  ),
  'Successfully',
